657:     
658:     sse.onmessage = (event) => {
659:         try {
660:             const msg = JSON.parse(event.data);
661:             if (msg.event === "new_scan") {
662:                 // Update local states
663:                 currentStats = msg.data.stats;
664:                 renderStatsUI();
665:                 loadScans();
666:                 loadAuditLogs();
667:             } else if (msg.event === "webhook_alert") {
668:                 // Update local states
669:                 currentStats = msg.data.stats;
670:                 renderStatsUI();
671:                 loadScans();
672:                 loadAuditLogs();
673: 
674:                 // Trigger sliding toast notification for threats
675:                 showThreatToast(msg.data);
676:             }
677:         } catch (e) {
678:             console.error("SSE parse error: ", e);
679:         }
680:     };
681: 
682:     sse.onerror = (e) => {
683:         console.log("SSE disconnected, retrying in 5s...");
684:         sse.close();
685:         setTimeout(connectSSE, 5000);
686:     };
687: }
